--
-- Table structure for table `player_national_stats`
--

DROP TABLE IF EXISTS `player_national_stats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `player_national_stats` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `player_id` int(11) DEFAULT NULL COMMENT 'FK player',
  `team_id` int(11) DEFAULT NULL COMMENT 'FK team (national)',
  `caps` int(11) DEFAULT NULL COMMENT 'Caps',
  `goals` int(11) DEFAULT NULL COMMENT 'Goals',
  `from_date` date DEFAULT NULL COMMENT 'Optional',
  `to_date` date DEFAULT NULL COMMENT 'Optional',
  `source_note` varchar(200) DEFAULT NULL COMMENT 'Source',
  PRIMARY KEY (`id`),
  KEY `fk_player_national_stats_player_id` (`player_id`),
  KEY `fk_player_national_stats_team_id` (`team_id`),
  CONSTRAINT `fk_player_national_stats_player_id` FOREIGN KEY (`player_id`) REFERENCES `player` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_player_national_stats_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

