  `player_id` int(11) NOT NULL COMMENT 'FK player',
  `team_id` int(11) NOT NULL COMMENT 'FK team',
  `from_date` date DEFAULT NULL COMMENT 'Début (NULL si inconnu)',
  `to_date` date DEFAULT NULL COMMENT 'Fin (NULL = en cours / inconnu)',
  `is_current` tinyint(1) NOT NULL DEFAULT 0 COMMENT '1 = club actuel (règle forte)' CHECK (`is_current` in (0,1)),
  `source_note` varchar(200) DEFAULT NULL COMMENT 'Source / note',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_pcm_exact` (`player_id`,`team_id`,`from_date`,`to_date`),
  KEY `ix_pcm_player_current` (`player_id`,`is_current`),
  KEY `ix_pcm_player_period` (`player_id`,`from_date`,`to_date`),
  KEY `ix_pcm_team_period` (`team_id`,`from_date`,`to_date`),
  KEY `ix_ptm_player_current` (`player_id`,`is_current`),
  KEY `ix_ptm_player_from_to` (`player_id`,`from_date`,`to_date`),
